import{H as e,R as t,U as n,V as r,W as i,j as a,nt as o,ot as s}from"./chunks/framework.B4R2P_rl.js";var c=JSON.parse(`{"title":"Migrating to Citizen 4","description":"Preview the Citizen 4 changes and migrate your wiki before the release","frontmatter":{"title":"Migrating to Citizen 4","description":"Preview the Citizen 4 changes and migrate your wiki before the release"},"headers":[],"relativePath":"guide/migrating-to-citizen-4.md","filePath":"guide/migrating-to-citizen-4.md","lastUpdated":1783554639000}`),l={name:`guide/migrating-to-citizen-4.md`};function u(a,c,l,u,d,f){let p=s(`CopyOrDownloadAsMarkdownButtons`);return o(),r(`div`,null,[c[0]||=t(`div`,{style:{display:`none`},hidden:`true`,"aria-hidden":`true`,"data-nosnippet":``},`Are you an LLM? You can read better optimized documentation at /mediawiki-skins-Citizen/guide/migrating-to-citizen-4.md for this page in Markdown format`,-1),c[1]||=t(`h1`,{id:`migrating-to-citizen-4`,tabindex:`-1`},[n(`Migrating to Citizen 4 `),t(`a`,{class:`header-anchor`,href:`#migrating-to-citizen-4`,"aria-label":`Permalink to “Migrating to Citizen 4”`},`​`)],-1),i(p),c[2]||=e(`<p>Citizen 4 will be released some time after MediaWiki 1.47 LTS. Use the <a href="./../contribute/preview-channel">preview channel</a> to test the changes.</p><h2 id="what-s-changing" tabindex="-1">What&#39;s changing <a class="header-anchor" href="#what-s-changing" aria-label="Permalink to “What&#39;s changing”">​</a></h2><ul><li><strong>New color token pipeline</strong> — colors are defined as <code>light-dark()</code> pairs built from primitive ramps instead of computed channel math. Most existing overrides keep working; see <a href="#migrate-your-token-overrides">Migrate your token overrides</a>.</li></ul><h2 id="migration-steps" tabindex="-1">Migration steps <a class="header-anchor" href="#migration-steps" aria-label="Permalink to “Migration steps”">​</a></h2><p>Preview the changes in your own browser, deploy your fixes behind a guard, then turn the whole wiki on when you&#39;re ready. Every step is safe to do ahead of the release.</p><h3 id="_1-try-it-in-your-browser" tabindex="-1">1. Try it in your browser <a class="header-anchor" href="#_1-try-it-in-your-browser" aria-label="Permalink to “1. Try it in your browser”">​</a></h3><p>Append <code>?citizenpreview=4</code> to any page URL on your wiki. The choice persists in a 24-hour cookie for your browser only; readers are unaffected. Append <code>?citizenpreview=0</code> to switch back.</p><h3 id="_2-deploy-fixes-behind-a-guard" tabindex="-1">2. Deploy fixes behind a guard <a class="header-anchor" href="#_2-deploy-fixes-behind-a-guard" aria-label="Permalink to “2. Deploy fixes behind a guard”">​</a></h3><p>Wrap your fixes so they apply only in the preview. The <code>citizen-v4</code> class is inert for stable readers, so a guarded fix is safe to deploy right away:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Where</th><th style="text-align:left;">How to target it</th></tr></thead><tbody><tr><td style="text-align:left;">CSS</td><td style="text-align:left;"><code>:root.citizen-v4 { … }</code></td></tr><tr><td style="text-align:left;">JavaScript</td><td style="text-align:left;"><code>document.documentElement.classList.contains( &#39;citizen-v4&#39; )</code></td></tr></tbody></table><p>The class stays on <code>&lt;html&gt;</code> for the whole Citizen 4 release, so your guarded fixes keep working after you upgrade. Drop the guards once you&#39;ve finished migrating; the class itself is removed in Citizen 5.</p><h3 id="_3-turn-it-on-wiki-wide" tabindex="-1">3. Turn it on wiki-wide <a class="header-anchor" href="#_3-turn-it-on-wiki-wide" aria-label="Permalink to “3. Turn it on wiki-wide”">​</a></h3><p>Once your fixes are in place, you can put the whole wiki on the preview with <a href="./../config/#wgcitizenpreview"><code>$wgCitizenPreview</code></a>:</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title="LocalSettings.php">LocalSettings.php</span></div><div class="language-php"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$wgCitizenPreview </span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div></div><p>Only the value <code>4</code> activates the preview during this cycle; <code>0</code> or any other value keeps the stable experience.</p><h2 id="migrate-your-token-overrides" tabindex="-1">Migrate your token overrides <a class="header-anchor" href="#migrate-your-token-overrides" aria-label="Permalink to “Migrate your token overrides”">​</a></h2><p>Most token names are unchanged — the big shift is <strong>how</strong> values resolve.</p><h3 id="light-and-dark-are-one-declaration-now" tabindex="-1">Light and dark are one declaration now <a class="header-anchor" href="#light-and-dark-are-one-declaration-now" aria-label="Permalink to “Light and dark are one declaration now”">​</a></h3><p>The new pipeline defines colors as <code>light-dark()</code> pairs and drives them with <code>color-scheme</code>.</p><p>The Citizen 3 pattern, which still works:</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#c13617;--shiki-dark:#FFAB70;">    --color-surface-0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#fffaf0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root.skin-theme-clientpref-night</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#c13617;--shiki-dark:#FFAB70;">    --color-surface-0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#16130e</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">@media</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ( prefers-color-scheme: dark ) {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    :root.skin-theme-clientpref-os</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#c13617;--shiki-dark:#FFAB70;">        --color-surface-0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#16130e</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The recommended Citizen 4 form — one declaration covers all three modes:</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root.citizen-v4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#c13617;--shiki-dark:#FFAB70;">    --color-surface-0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: light-dark( </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#fffaf0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">#16130e</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> );</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The <code>light-dark()</code> form is also simpler, and it lets custom themes build on the base — a theme sets <code>color-scheme</code>, overrides only the colors it changes, and everything else falls back to the right light or dark value.</p><h3 id="removed-tokens" tabindex="-1">Removed tokens <a class="header-anchor" href="#removed-tokens" aria-label="Permalink to “Removed tokens”">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">If you overrode…</th><th style="text-align:left;">To migrate</th></tr></thead><tbody><tr><td style="text-align:left;">A surface, text, border, or background token</td><td style="text-align:left;">Nothing — the names are unchanged.</td></tr><tr><td style="text-align:left;">A color&#39;s channel to retune it (e.g. <code>--color-base-oklch__l</code>)</td><td style="text-align:left;">Set the color token itself (e.g. <code>--color-base</code>).</td></tr><tr><td style="text-align:left;">An HSL color fallback (<code>…-hsl__*</code>)</td><td style="text-align:left;">Nothing — Citizen 4 drops the HSL fallback, but modern browsers already used the OKLCH colors in Citizen 3.</td></tr><tr><td style="text-align:left;">A <code>--delta-lightness-*</code> state or surface delta</td><td style="text-align:left;">Set the affected token directly (e.g. <code>--color-surface-1--hover</code>).</td></tr><tr><td style="text-align:left;">The primary-color hue (<code>--color-progressive-oklch__h</code>)</td><td style="text-align:left;">See <a href="#rebranding-the-primary-color">Rebranding the primary color</a>.</td></tr></tbody></table><details class="details custom-block"><summary>Full list of removed tokens</summary><p>Channel key: <code>__l</code> lightness, <code>__c</code> chroma, <code>__s</code> saturation, <code>__h</code> hue.</p><p><strong>State and surface deltas:</strong></p><ul><li><code>--delta-lightness-hover-state</code></li><li><code>--delta-lightness-active-state</code></li><li><code>--delta-lightness-state-base</code></li><li><code>--delta-lightness-surface-base</code></li></ul><p><strong>OKLCH channels:</strong></p><ul><li><code>--color-base-oklch__c</code>, <code>--color-base-oklch__l</code></li><li><code>--color-disabled-oklch__c</code>, <code>--color-disabled-oklch__l</code></li><li><code>--color-emphasized-oklch__c</code>, <code>--color-emphasized-oklch__l</code></li><li><code>--color-placeholder-oklch__c</code>, <code>--color-placeholder-oklch__l</code></li><li><code>--color-progressive-oklch__c</code>, <code>--color-progressive-oklch__l</code></li><li><code>--color-subtle-oklch__c</code>, <code>--color-subtle-oklch__l</code></li><li><code>--color-surface-0-oklch__c</code>, <code>--color-surface-0-oklch__l</code></li><li><code>--color-surface-1-oklch__c</code>, <code>--color-surface-1-oklch__l</code></li><li><code>--color-surface-2-oklch__c</code>, <code>--color-surface-2-oklch__l</code></li><li><code>--color-surface-3-oklch__c</code>, <code>--color-surface-3-oklch__l</code></li><li><code>--color-surface-4-oklch__c</code>, <code>--color-surface-4-oklch__l</code></li><li><code>--shadow-color-oklch__c</code>, <code>--shadow-color-oklch__l</code></li></ul><p><strong>HSL channels:</strong></p><ul><li><code>--color-base-hsl__l</code>, <code>--color-base-hsl__s</code></li><li><code>--color-disabled-hsl__l</code>, <code>--color-disabled-hsl__s</code></li><li><code>--color-emphasized-hsl__l</code>, <code>--color-emphasized-hsl__s</code></li><li><code>--color-placeholder-hsl__l</code>, <code>--color-placeholder-hsl__s</code></li><li><code>--color-subtle-hsl__l</code>, <code>--color-subtle-hsl__s</code></li><li><code>--color-surface-0-hsl__l</code>, <code>--color-surface-0-hsl__s</code></li><li><code>--color-surface-1-hsl__l</code>, <code>--color-surface-1-hsl__s</code></li><li><code>--color-surface-2-hsl__l</code>, <code>--color-surface-2-hsl__s</code></li><li><code>--color-surface-3-hsl__l</code>, <code>--color-surface-3-hsl__s</code></li><li><code>--color-surface-4-hsl__l</code>, <code>--color-surface-4-hsl__s</code></li><li><code>--shadow-color-hsl__l</code>, <code>--shadow-color-hsl__s</code></li></ul><p><strong>Standalone channels:</strong></p><ul><li><code>--background-color-subtle__l</code>, <code>--background-color-subtle__s</code></li><li><code>--color-destructive__h</code>, <code>--color-destructive__l</code></li><li><code>--color-success__h</code>, <code>--color-success__l</code></li><li><code>--color-warning__h</code>, <code>--color-warning__l</code></li></ul></details><h3 id="rebranding-the-primary-color" tabindex="-1">Rebranding the primary color <a class="header-anchor" href="#rebranding-the-primary-color" aria-label="Permalink to “Rebranding the primary color”">​</a></h3><p>Move your hue override from <code>--color-progressive-oklch__h</code> to <code>--color-primary-oklch__h</code>. The value is the same:</p><div class="language-css"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;">/* Citizen 3 */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#c13617;--shiki-dark:#FFAB70;">    --color-progressive-oklch__h</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">150</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;">/* Citizen 4 preview */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">:root.citizen-v4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#c13617;--shiki-dark:#FFAB70;">    --color-primary-oklch__h</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">150</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Citizen 4 can tint the neutral surfaces separately from the accent. <code>--color-neutral-oklch__h</code> sets their hue and defaults to the primary hue — set it to a different value to decouple the two.</p>`,31)])}var d=a(l,[[`render`,u]]);export{c as __pageData,d as default};